static uint32_t readl(unsigned long addr)
{
	uint32_t value = *(volatile uint32_t*)addr;
	return value;
}

static void writel(uint32_t value, unsigned long addr)
{
	*(volatile uint32_t*)addr = value;
}

static void writels(uint32_t value, unsigned long addr)
{
	uint32_t tmp = readl(addr);
	tmp |= value;
	writel(tmp, addr);
}

static void writelc(uint32_t value, unsigned long addr)
{
	uint32_t tmp = readl(addr);
	tmp &= (~value);
	writel(tmp, addr);
}

static void writelr(uint32_t value, unsigned long addr, uint32_t start, uint32_t bit)
{
	uint32_t region = (0xFFFFFFFFU << ( start + bit )) | (0xFFFFFFFFULL >> ( 32 - start ));
	uint32_t tmp = readl(addr);
	tmp &= region;
	tmp |= (~region) & (value << start);
	writel(tmp, addr);
}

