// width / height / address must be 16 aligned
volatile unsigned int debug_cnt = 1;
void fast_jpeg(uint32_t jpg, uint32_t jpg_len, uint32_t y, uint32_t uv)
{
	int cnt = 100;
	int status = 0;

	// jpgd soft reset
	writels(0x00000040, 0x24000030);
	writelc(0x00000040, 0x24000030);

	writels(0x00000006, 0x24000028);
	// jpgd enable clk
	writels(0x00000009, 0x2400002c);

	writel(0x00000001, 0x26100004);
	writel(jpg_len, 0x26100050);
	writel(0x00000001, 0x26100008);
	writel(jpg,       0x2610003C); /* JPG  */
	writel(y,         0x26100034); /* Y    */
	writel(uv ,       0x26100040); /* UV   */
	writel(0x00000000, 0x26100058);
	writels(0x0000000A, 0x26100014);
	writel(0x80000001, 0x26100010);

	// wait decode done
	while (cnt-- > 0) {
		udelay(1000);
		status = readl(0x26100004);
		if ((status & 0x01) != 0) {
			printf("JPEG: decode done.\n");

			writels(0x00000001, 0x26100004);
			break;
		}
	}

	if (cnt <= 0) {
		printf("JPEG: decode timeout.\n");
	}
}

#define LOGO_LOCATION (0x40000000+128*1024*1024-1024*600*4)

void boot_logo(void)
{
#ifdef YUV_LOGO
#ifdef JPEG_LOGO
	fast_jpeg((unsigned long)&tank_jpg[0], tank_jpg_len, LOGO_LOCATION, LOGO_LOCATION + 256*144);
	fast_osd(0, 0, 1024, 600, LOGO_LOCATION, 256, 256, 144);
#else
    printf("start fast osd - yuv!\n");
    memcpy((void*)LOGO_LOCATION, &t_yuv[0], sizeof(t_yuv));
	fast_osd(0, 0, 1024, 600, LOGO_LOCATION, 256, 256, 150);
#endif
#else
    printf("start fast osd - rgb!\n");
    memcpy((void*)LOGO_LOCATION, &t_argb[0], sizeof(t_yuv));
	fast_osd(412, 240, -1, -1, LOGO_LOCATION, 200, 200, 120);
#endif
}
